// Look up a stencil by name (for debugging)
static inline const StencilDef* findStencil(const char* name) {
    for (int i = 0; i < NumStencils; i++) {
        if (__builtin_strcmp(stencilTable[i].name, name) == 0)
            return &stencilTable[i];
    }
    return nullptr;
}

